  "consolidated_rubrics": [
    {
      "id": "explicit_textual_grounding",
      "name": "Explicit Textual Grounding",
      "question": "Can every claim in the memory item be directly mapped to a specific utterance or segment in the conversation history?",
      "why_it_matters": "Prevents hallucination and ensures the memory is based on actual user input.",
      "failure_examples": [
        "Memory item contains details not mentioned in the text",
        "Memory item infers a preference the user never explicitly stated"
      ],
      "source_trace": [
        {
          "model": "gemini",
          "rubric_id": "grounding_verifiability"
        },
        {
          "model": "deepseek",
          "rubric_id": "explicit_textual_support"
        },
        {
