      "id": "entity_attribution_accuracy",
      "name": "Entity Attribution Accuracy",
      "question": "Are attributes, preferences, and actions correctly assigned to the specific speaker or entity they belong to?",
      "why_it_matters": "Prevents cross-talk errors where the model confuses the user's traits with the assistant's or another participant's.",
      "failure_examples": [
        "Assigning the user's dietary restriction to the assistant",
        "Confusing two different people mentioned in the conversation"
      ],
      "source_trace": [
