      "id": "temporal_correctness",
      "name": "Temporal Correctness",
      "question": "Does the memory item correctly distinguish between past events, current states, and future intentions?",
      "why_it_matters": "Ensures the model does not treat a past preference as a current one or a future plan as a completed action.",
      "failure_examples": [
        "Stating a planned trip as a completed event",
        "Retaining an outdated address after the user provided a new one"
      ],
      "source_trace": [
