      "id": "fact_atomicity",
      "name": "Fact Atomicity",
      "question": "Does each memory item contain exactly one distinct, independent fact?",
      "why_it_matters": "Atomic facts are easier to update, delete, or retrieve without side effects.",
      "failure_examples": [
        "Combining a user's job title and their favorite color in one item",
        "Bundling a list of three unrelated hobbies into a single entry"
