      "id": "redundancy_check",
      "name": "Redundancy Check",
      "question": "Is the information in this item unique, or is it already covered by another existing memory item?",
      "why_it_matters": "Redundancy bloats the memory store and increases the risk of conflicting information.",
      "failure_examples": [
        "Two items stating the same fact with slightly different wording",
        "A general item that is entirely contained within a more specific item"
      ],
      "source_trace": [
