      "id": "contradiction_avoidance",
      "name": "Contradiction Avoidance",
      "question": "Does the memory set contain any mutually exclusive facts?",
      "why_it_matters": "Contradictions render the memory store unreliable for decision-making.",
      "failure_examples": [
        "One item saying the user is vegan, another saying they love steak",
        "Conflicting location data for the same entity"
