          "model": "minimax",
          "rubric_id": "inference_boundary"
        }
      ]
    },
    {
      "id": "no_hallucination",
      "name": "No Hallucination",
      "question": "Are there any fact memory items that contain information not present or implied in the conversation?",
      "why_it_matters": "Hallucinations introduce false information.",
      "failure_examples": [
        "Memory item says 'Eve has a PhD' but conversation never mentions education.",
        "Memory item says 'Frank is married' but conversation only mentions his girlfriend."
      ],
      "source_trace": [
